BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  {
    ?elem vocab:NamedElement_name "APS Mission" .
    ?elem ?prop ?value .
  }
  UNION
  {
    ?elem vocab:NamedElement_name "The APS and Its Role in TMT" .
    ?elem ?prop ?value .
  }
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?commentBody WHERE {
  {
    ?elem vocab:NamedElement_name "APS Mission" .
    ?elem vocab:Element_ownedComment ?comment .
    ?comment vocab:Comment_body ?commentBody .
  }
  UNION
  {
    ?elem vocab:NamedElement_name "The APS and Its Role in TMT" .
    ?elem vocab:Element_ownedComment ?comment .
    ?comment vocab:Comment_body ?commentBody .
  }
}
LIMIT 10
